#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Self-contained XMind -> standalone HTML viewer converter.

This single file embeds the viewer CSS and JS, so no template folder is needed.
Pillow is optional: if installed, images are re-encoded to lossless WebP when
that is smaller; if not installed, the original image bytes are embedded as-is.

Usage:
    python xmind2html.py                       # convert every *.xmind next to this script
    python xmind2html.py a.xmind b.xmind       # convert specific files
    python xmind2html.py C:\\some\\folder        # convert every *.xmind under a folder (recursive)
    python xmind2html.py *.xmind                # globs work too

Output .html is written next to each source .xmind.
"""

from __future__ import annotations

import base64
import glob
import io
import json
import math
import os
import sys
import zipfile
from concurrent.futures import ThreadPoolExecutor
from pathlib import Path
from typing import Any

try:
    from PIL import Image  # type: ignore
    _HAS_PIL = True
except Exception:  # noqa: BLE001
    _HAS_PIL = False


# Embedded viewer templates (base64 of the original viewer.css / viewer.js).
VIEWER_CSS_B64 = ""
VIEWER_JS_B64 = ""


def _viewer_css() -> str:
    return base64.b64decode(VIEWER_CSS_B64).decode("utf-8")


def _viewer_js() -> str:
    return base64.b64decode(VIEWER_JS_B64).decode("utf-8")


def _image_to_data_uri(item: tuple[str, bytes]) -> tuple[str, str]:
    """Embed one image as a data URI, preferring smaller lossless WebP output."""
    name, data = item
    if _HAS_PIL:
        try:
            img = Image.open(io.BytesIO(data))
            img = img.convert("RGBA" if img.mode in ("RGBA", "P") else "RGB")
            buf = io.BytesIO()
            img.save(buf, format="WEBP", lossless=True, method=6)
            img.close()
            webp = buf.getvalue()
            if len(webp) < len(data):
                return name, "data:image/webp;base64," + base64.b64encode(webp).decode()
        except Exception:  # noqa: BLE001
            pass

    ext = name.rsplit(".", 1)[-1].lower()
    mime = {"png": "image/png", "jpg": "image/jpeg", "jpeg": "image/jpeg"}.get(ext, "image/" + ext)
    return name, "data:" + mime + ";base64," + base64.b64encode(data).decode()


def load_xmind(path: str | os.PathLike[str]) -> tuple[list[dict[str, Any]], dict[str, str]]:
    """Read content.json and resource images from an XMind archive."""
    raw_images: dict[str, bytes] = {}
    with zipfile.ZipFile(path, "r") as archive:
        with archive.open("content.json") as f:
            content = json.load(f)
        for name in archive.namelist():
            basename = name.split("/")[-1]
            if name.startswith("resources/") and "." in basename:
                with archive.open(name) as f:
                    raw_images[name] = f.read()

    images: dict[str, str] = {}
    with ThreadPoolExecutor() as pool:
        for name, uri in pool.map(_image_to_data_uri, raw_images.items()):
            images[name] = uri
    return content, images


def get_title(topic: dict[str, Any]) -> str:
    title = topic.get("title", "").strip()
    if title:
        return title
    for part in topic.get("attributedTitle", []):
        title = part.get("text", "").strip()
        if title:
            return title
    return ""


def calc_content_width(title: str, depth: int, image_width: int) -> int:
    font_size = {0: 16, 1: 14, 2: 13, 3: 13}.get(depth, 12)
    max_width = {0: 300, 1: 270, 2: 240, 3: 210}.get(depth, 190)
    min_width = {0: 120, 1: 100, 2: 85, 3: 75}.get(depth, 65)

    if title:
        cjk = sum(1 for char in title if "\u4e00" <= char <= "\u9fff")
        rest = len(title) - cjk
        text_width = min(cjk * font_size + rest * int(font_size * 0.55), max_width)
    else:
        text_width = 0
    return max(min_width, text_width, image_width or 0)


def estimate_node_size(title: str, depth: int, image_width: int, image_height: int) -> tuple[int, int]:
    horizontal_padding = 24
    vertical_padding = 16
    content_width = calc_content_width(title, depth, image_width)
    node_width = content_width + horizontal_padding

    if title:
        font_size = {0: 16, 1: 14, 2: 13, 3: 13}.get(depth, 12)
        line_height = max(18, math.ceil(font_size * 1.5))
        cjk = sum(1 for char in title if "\u4e00" <= char <= "\u9fff")
        rest = len(title) - cjk
        text_px_width = cjk * font_size + rest * int(font_size * 0.55)
        available_width = max(1, content_width - 12)
        lines = max(1, math.ceil(text_px_width / available_width))
        text_height = lines * line_height
    else:
        text_height = 0

    image_display_height = 0
    if image_width > 0 and image_height > 0:
        scale = min(1.0, content_width / max(1, image_width))
        image_display_height = math.ceil(image_height * scale) + 4

    node_height = text_height + image_display_height + vertical_padding
    return node_width, max(node_height, 32)


def build_tree(
    topic: dict[str, Any],
    images: dict[str, str],
    image_index: dict[str, int],
    depth: int = 0,
) -> dict[str, Any]:
    title = get_title(topic)
    image_idx = -1
    image_width = 0
    image_height = 0

    image_info = topic.get("image")
    if image_info:
        key = image_info.get("src", "").replace("xap:", "")
        if key in images:
            if key not in image_index:
                image_index[key] = len(image_index)
            image_idx = image_index[key]
            image_width = image_info.get("width", 0)
            image_height = image_info.get("height", 0)

    node_width, node_height = estimate_node_size(title, depth, image_width, image_height)
    children_raw = topic.get("children", {}).get("attached", [])
    children = [build_tree(child, images, image_index, depth + 1) for child in children_raw]

    node: dict[str, Any] = {"i": topic.get("id", str(depth)), "t": title, "w": node_width, "h": node_height}
    if image_idx >= 0:
        node["p"] = image_idx
        node["pw"] = image_width
        node["ph"] = image_height
    href = topic.get("href", "")
    if href.startswith("xmind:#"):
        node["lnk"] = href[7:]
    if children:
        node["c"] = children
    return node


def html_escape(value: Any) -> str:
    return (
        str(value)
        .replace("&", "&amp;")
        .replace("<", "&lt;")
        .replace(">", "&gt;")
        .replace('"', "&quot;")
    )


def ordered_image_array(images: dict[str, str], image_index: dict[str, int]) -> list[str]:
    flat = [""] * len(image_index)
    for key, idx in image_index.items():
        flat[idx] = images[key]
    return flat


def build_html(
    content: list[dict[str, Any]],
    images: dict[str, str],
    image_index: dict[str, int] | None = None,
    filename: str = "",
) -> str:
    image_index = image_index if image_index is not None else {}
    sheet = content[0] if content else {}
    root = sheet.get("rootTopic", {})
    root_title = get_title(root) or filename

    tree = build_tree(root, images, image_index)
    tree_json = json.dumps(tree, ensure_ascii=False)
    images_json = json.dumps(ordered_image_array(images, image_index), ensure_ascii=False)
    viewer_css = _viewer_css()
    viewer_js = _viewer_js()
    safe_title = html_escape(root_title)

    return f"""<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1,maximum-scale=5,user-scalable=yes"/>
<title>{safe_title}</title>
<style>html,body{{user-select:none!important;touch-action:auto!important}}</style>
<style>{viewer_css}</style>
</head>
<body>
<div id="bar">
  <span id="bar-title">&#129504; {safe_title}</span>
  <input id="search" type="text" placeholder="&#128269; Search..." oninput="doSearch(this.value)"/>
  <span id="s-info"></span>
  <button class="btn" onclick="fitView()">Fit View</button>
  <button class="btn" onclick="expandAll()">Expand All</button>
  <button class="btn" onclick="collapseLevel(1)">Collapse to Level 1</button>
  <button class="btn" onclick="collapseLevel(2)">Collapse to Level 2</button>
  <button class="btn" onclick="goHome()">&#127968; Home</button>
  <span id="zoom-info">100%</span>
</div>
<div id="sidebar">
  <div id="sb-header">
    <span id="sb-count">0 results</span>
    <span id="sb-close" onclick="closeSidebar()" title="Close">✕</span>
  </div>
  <div id="sb-list"></div>
</div>
<div id="wrap">
  <div id="stage"><svg id="links"></svg></div>
</div>
<div id="tip">Wheel to zoom · Drag to pan · Click a node to expand or collapse</div>
<script>
const IMG={images_json};
const RAW_TREE={tree_json};
{viewer_js}
</script>
<div id="mzoom">
  <button onclick="zoomBy(1.4)" title="Zoom in">＋</button>
  <button onclick="zoomBy(0.7)" title="Zoom out">－</button>
  <button onclick="goHome()" title="Home" style="font-size:1rem">&#127968;</button>
</div>
</body>
</html>"""


def convert_one(src: Path) -> Path:
    dst = src.with_suffix(".html")
    content, images = load_xmind(src)
    html = build_html(content, images, {}, src.name)
    dst.write_text(html, encoding="utf-8")
    return dst


def gather_xmind_files(args: list[str], script_dir: Path) -> list[Path]:
    files: list[Path] = []
    if not args:
        files.extend(sorted(script_dir.glob("*.xmind")))
    else:
        for raw in args:
            p = Path(raw)
            if p.is_dir():
                files.extend(sorted(p.rglob("*.xmind")))
            elif p.is_file():
                files.append(p)
            else:
                matched = [Path(m) for m in glob.glob(raw, recursive=True)]
                files.extend(sorted(m for m in matched if m.is_file()))

    seen: set[Path] = set()
    result: list[Path] = []
    for f in files:
        rp = f.resolve()
        if rp.suffix.lower() != ".xmind":
            continue
        if rp not in seen:
            seen.add(rp)
            result.append(f)
    return result


def main() -> int:
    script_dir = Path(__file__).resolve().parent
    xmind_files = gather_xmind_files(sys.argv[1:], script_dir)

    if not xmind_files:
        print("No .xmind files found to convert.")
        print("Drag .xmind files onto the .bat, or place this next to your .xmind files and run it.")
        return 1

    if not _HAS_PIL:
        print("(Note: Pillow not installed -> images embedded as-is, no WebP optimization. Output still works.)")

    ok = 0
    failed = 0
    for src in xmind_files:
        try:
            dst = convert_one(src)
            kb = round(dst.stat().st_size / 1024, 1)
            print(f"[OK]   {src.name}  ->  {dst.name}  ({kb} KB)")
            ok += 1
        except Exception as exc:  # noqa: BLE001
            print(f"[FAIL] {src.name}  ({exc})")
            failed += 1

    print("-" * 48)
    print(f"Done. {ok} converted, {failed} failed, {len(xmind_files)} total.")
    return 0 if failed == 0 else 2


if __name__ == "__main__":
    sys.exit(main())


